#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define pii pair<int,int>
#define fr first
#define se second
#define pb push_back
using namespace std;
const LL N = 5e4+5;
struct node{LL a,b,c,d,e,val,id,t;}p[N],h[N],s[N];
LL m,n,ppp,ans,r[N],dp[N];map<LL,LL> mp;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool operator != (const node &A , const node &B){
    return (A.a!=B.a||A.b!=B.b||A.c!=B.c||A.d!=B.d||A.val!=B.val);
}
bool cmp1(node d1,node d2){
    if(d1.a!=d2.a)return d1.a<d2.a;
    if(d1.b!=d2.b)return d1.b<d2.b;
    if(d1.c!=d2.c)return d1.c<d2.c;
    return (d1.d<d2.d||(d1.d==d2.d&&d1.val>d2.val));
}
bool cmp2(node d1,node d2){
    if(d1.b!=d2.b)return d1.b<d2.b;
    if(d1.c!=d2.c)return d1.c<d2.c;
    return (d1.d<d2.d||(d1.d==d2.d&&d1.val>d2.val));
}
bool cmp3(node d1,node d2){
    if(d1.c!=d2.c)return d1.c<d2.c;
    return (d1.d<d2.d||(d1.d==d2.d&&d1.val>d2.val));
}
void clr(LL x){while(x<=ppp)r[x]=0,x+=x&-x;return;}
void add(LL x,LL k){while(x<=ppp)r[x]=max(r[x],k),x+=x&-x;return;}
LL ask(LL x){LL sum=0;while(x)sum=max(sum,r[x]),x-=x&-x;return sum;}
void CDQ2(LL l,LL r){
    if(l==r)return;
    LL mid=(l+r)>>1;CDQ2(l,mid);
    stable_sort(h+l,h+mid+1,cmp3);
    stable_sort(h+mid+1,h+r+1,cmp3);
    LL p1=l,p2=mid+1;
    for(LL i=l;i<=r;i++)
        if((p2>r)||(p1<=mid&&h[p1].c<=h[p2].c))
            {if(!h[p1].e)add(h[p1].d,dp[h[p1].id]);p1++;}
        else{if(h[p2].e)dp[h[p2].id]=max(dp[h[p2].id],ask(h[p2].d)+h[p2].t*h[p2].val);p2++;}
    for(LL i=l;i<=mid;i++)if(!h[i].e)clr(h[i].d);
    stable_sort(h+mid+1,h+r+1,cmp2);CDQ2(mid+1,r);return;
}
void CDQ1(LL l,LL r){
    if(l==r)return;
    LL mid=(l+r)>>1;CDQ1(l,mid);
    for(LL i=l;i<=r;i++)h[i]=s[i],h[i].e=(i>mid);
    stable_sort(h+l,h+r+1,cmp2);
    CDQ2(l,r);CDQ1(mid+1,r);return;
}
int main(){
    cin>>m;ans=-0x3f3f3f3f3f3f3f3f;
    memset(dp,-0x3f,sizeof(dp));
    for(LL i=1;i<=m;i++)
        cin>>p[i].a>>p[i].b>>p[i].c>>p[i].d>>p[i].val;
    for(LL i=1;i<=m;i++)mp[p[i].d]=1;
    ppp=0;for(auto &it:mp)it.se=(++ppp);
    for(LL i=1;i<=m;i++)p[i].d=mp[p[i].d];
    stable_sort(p+1,p+m+1,cmp1);
    for(LL i=1;i<=m;s[n].t++,i++)
        if(p[i]!=p[i-1])s[++n]=p[i],s[n].id=n;
    for(LL i=1;i<=n;i++)if(p[i].val<0)s[i].t=1;
    for(LL i=1;i<=n;i++)dp[i]=max(p[i].val,s[i].t*p[i].val);
    stable_sort(s+1,s+n+1,cmp1);CDQ1(1,n);
    for(LL i=1;i<=n;i++)ans=max(ans,dp[i]);
    cout<<ans<<"\n";
    return 0;
}
